  ('elementary-6e11b43e-moex-00180', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '臺灣原住民族正名運動首先在1980年代由那一個組織提出正名的要求？', '["臺灣原住民土地返還協會", "臺灣原住民教授協會", "原住民族青年陣線", "臺灣原住民族權利促進會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00181', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '1954 年，陸續有排灣族人從屏東三地門、瑪家鄉、泰武等地遷移至高雄市中華路一帶，形成了一個超過 60年的都市排灣族部落，請問為下列那個部落？', '["塔拉南部落", "拉芙蘭部落", "三鶯部落", "拉瓦克部落"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00182', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '1951年1月臺灣省政府公布「山地施政要點」共22條，下列敘述何者錯誤？', '["此政策的制定是省政府欲將原住民行政事務納入一般行政當中，促使「山地平地化」的目標達成", "積極獎勵國語、國文推行，以各項有效辦法，啟發山胞學習國語國文興趣", "山地學校之教學，應一律使用國語，必要時得用山地語輔助，絕對禁用日語", "山地國民學校之校長教員不懂國語者，一律飭令限期補習，期間仍不懂者，調到非原住民區任職"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00183', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '中華民國政府沿襲日治時期的「蕃人所要地」制度並更名為「山地保留地制度」。山地保留地制度與蕃人 所要地制度的內涵在1966年以前基本上一致，下列敘述何者正確？', '["1966年以前原住民族已經擁有土地所有權", "1966年以前僅賦予原住民族使用土地之權限", "1966年以前已超過55%的保留地有登記所有權", "1966年以前的原住民族保留地面積比之後的土地面積還小"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00184', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '1960、1970年代原住民族人口遷徙的原因有許多，下列敘述何者錯誤？', '["山地農業相對式微", "部落工作機會不足", "都市勞動力需求", "都市居住環境佳"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00185', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '原住民族的行政組織，在民國35年之後將「山地警務」以外的「土地業務」全部劃歸民政處接辦，結束 警察專管。民政處改廳後，37年7月至38年4月曾在民政廳之下設立什麼單位，總攬山地業務？', '["山胞委員會", "山地行政處", "山地委員會", "山胞行政處"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00186', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '下列何者不是原住民族權利運動時期的重要訴求？', '["1983年至1988年打破「吳鳳神話故事」系列抗爭活動", "1987年起蘭嶼雅美族反核廢運動", "1988年至1993年還我土地運動", "1998年至2003年大家都來寫部落史"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00187', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '1960 年代中期，隨著政府的山地政策逐漸朝向開發與資本化，原住民族青年離鄉、前往都市就學與就業 者逐漸增多，他們在平地生活的適應與調適需求也隨之增長。下列那一個不是當時協助原住民族群適應都 市生活的機構或組織？', '["臺灣原住民族權利促進會", "山地服務中心", "旅北山地大專基督教青年聯誼會", "原住民漁民中心"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00188', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '1975年2月17日，政府假稱「臺灣山地獨立運動組織」，將原住民5位人士依照懲治叛亂條例提起公 訴，被處以3年至9年不等的有期徒刑。下列那一位不是這個事件中遭到逮捕的人士？', '["呂文華", "林瑞昌", "杜文義", "鄭榮祥"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL)
